            if (command == "!plugin") {
                if (args.size() < 2) {
                    std::cout << loader.GetCLIHelp() << std::endl;
                    continue;
                }
                std::string subcmd = args[1];
                
                if (subcmd == "load" && args.size() > 2) {
                    if (loader.LoadPlugin(args[2])) std::cout << "Plugin loaded.\n";
