                    for(auto* p : plugins) {
                        std::cout << (p->enabled ? "[*] " : "[ ] ") << p->id << " (" << p->version << ")\n";
                    }
                }
                else if (subcmd == "help" && args.size() > 2) {
                    std::cout << loader.GetPluginHelp(args[2]) << std::endl;
                }
            }
            else if (command == "!memory") {
                 if (args.size() > 2 && args[1] == "load") {
                     // Simulate context sizing logic
                     size_t size = std::stoull(args[2]);
                     std::cout << "Allocating memory module: " << size << " tokens...\n";
                     loader.LoadMemoryModule("internal_memory.vsix", size);
                 }
            }
        }
        // 2. Agent/AI Commands (/)
        else if (command[0] == '/') {
            if (command == "/help") {
                std::cout << loader.GetCLIHelp() << std::endl;
            }
            else if (command == "/exit") {
                break;
            }
            else {
                // Route to plugins that registered this command
                // In a real scenario, this would check `loader.ExecuteCommand` or route to specific AI logic
                bool handled = loader.ExecuteCommand(command);
                if (!handled) {
                    std::cout << COLOR_YELLOW << "Processing Agent Task: " << command << "..." << COLOR_RESET << "\n";
                    // Simulate processing delay
                    std::cout << ">> Thought Process Initiated...\n";
                    std::cout << ">> Context Window: " << loader.GetAvailableMemoryModules().size() << " modules active.\n";
                    std::cout << ">> Result: Command executed successfully via Engine Core.\n";
                }
            }
        }
        // 3. Fallback
        else {
             std::cout << "Unknown command. Try /help\n";
        }
    }

    return 0;
}
