## 2. Real Tokenizer (BPE - Byte Pair Encoding)

```cpp
// tokenizer.cpp - Real BPE implementation
#include <string>
#include <vector>
#include <unordered_map>
#include <regex>
#include <algorithm>

struct Tokenizer {
    std::unordered_map<std::string, int> encoder;
    std::unordered_map<int, std::string> decoder;
    std::vector<std::pair<std::string, std::string>> bpe_merges;
    
    // GPT-2 style regex pattern
    std::regex pat = std::regex(R"('s|'t|'re|'ve|'m|'ll|'d| ?\p{L}+| ?\p{N}+| ?[^\s\p{L}\p{N}]+|\s+(?!\S)|\s+)");
    
    // Load from vocab file (reverse engineered from GPT-2/LLaMA)
    bool load(const std::string& vocab_path) {
        std::ifstream f(vocab_path);
        if (!f) return false;
        
        std::string line;
        int idx = 0;
        while (std::getline(f, line)) {
            encoder[line] = idx;
            decoder[idx] = line;
            idx++;
        }
        
        // Load merges (pairs that get combined)
        std::ifstream m(vocab_path + ".merges");
        while (std::getline(m, line)) {
            if (line.empty() || line[0] == '#') continue;
            auto space = line.find(' ');
            bpe_merges.push_back({line.substr(0, space), line.substr(space+1)});
        }
        return true;
    }
    
    // Byte-level BPE encoding
    std::vector<int> encode(const std::string& text) {
        std::vector<int> tokens;
        
        // Split by regex pattern
        std::sregex_iterator iter(text.begin(), text.end(), pat);
        std::sregex_iterator end;
        
        for (; iter != end; ++iter) {
            std::string token = (*iter).str();
            
            // Convert to bytes first (for unicode)
            std::vector<std::string> word;
            for (unsigned char c : token) {
                word.push_back(std::string(1, c));
            }
            
            // Apply BPE merges
            while (word.size() > 1) {
                // Find highest priority merge
                int best_idx = -1;
                size_t best_rank = bpe_merges.size() + 1;
                
                for (size_t i = 0; i < word.size() - 1; i++) {
                    std::string pair = word[i] + " " + word[i+1];
                    auto it = std::find_if(bpe_merges.begin(), bpe_merges.end(),
                        [&](const auto& m) { return m.first + " " + m.second == pair; });
                    if (it != bpe_merges.end()) {
                        size_t rank = std::distance(bpe_merges.begin(), it);
                        if (rank < best_rank) {
                            best_rank = rank;
                            best_idx = i;
                        }
                    }
                }
                
                if (best_idx == -1) break;
                
                // Apply merge
                word[best_idx] = word[best_idx] + word[best_idx + 1];
                word.erase(word.begin() + best_idx + 1);
            }
            
            // Convert to token IDs
            for (const auto& w : word) {
                auto it = encoder.find(w);
                if (it != encoder.end()) tokens.push_back(it->second);
                else tokens.push_back(encoder["<|unk|>"]);
            }
        }
        
        return tokens;
    }
    
    std::string decode(const std::vector<int>& tokens) {
        std::string text;
        for (int t : tokens) {
            auto it = decoder.find(t);
            if (it != decoder.end()) text += it->second;
        }
        return text;
    }
};
